mapper.select:
SELECT p.id, p.slug, p.type, p.title, p.description, p.published_at, (SELECT COUNT(*) FROM post_views WHERE post_id = p.id) AS view_count, (SELECT COUNT(*) FROM post_likes WHERE post_id = p.id) AS like_count, (SELECT COUNT(*) FROM comments WHERE post_id = p.id) AS comment_count FROM posts p
p.type = #{type}
ORDER BY p.published_at DESC LIMIT #{size} OFFSET #{offset}

SELECT EXISTS(
    SELECT 1 FROM post_views
    WHERE post_id = #{postId}
      AND ip_hash = #{ipHash}
      AND viewed_at > NOW() - INTERVAL '1 hour'
)
